import{_ as a,o as e,c as s,ao as t}from"./chunks/framework.CfCmx4qt.js";const c=JSON.parse('{"title":"Limitations & configuration","description":"","frontmatter":{},"headers":[],"relativePath":"limitations.md","filePath":"limitations.md","lastUpdated":null}'),n={name:"limitations.md"};function l(o,i,h,d,p,r){return e(),s("div",null,[...i[0]||(i[0]=[t(`<h1 id="Limitations-and-configuration" tabindex="-1">Limitations &amp; configuration <a class="header-anchor" href="#Limitations-and-configuration" aria-label="Permalink to &quot;Limitations &amp; configuration {#Limitations-and-configuration}&quot;">​</a></h1><p>This page collects the constraints of the CTLie operators and the knobs available to configure them.</p><h2 id="Limitations" tabindex="-1">Limitations <a class="header-anchor" href="#Limitations" aria-label="Permalink to &quot;Limitations {#Limitations}&quot;">​</a></h2><h3 id="No-in-place-support" tabindex="-1">No in-place support <a class="header-anchor" href="#No-in-place-support" aria-label="Permalink to &quot;No in-place support {#No-in-place-support}&quot;">​</a></h3><p>The operators are defined for <strong>out-of-place</strong> objects only. A field built with <code>is_inplace=true</code> (mutability <a href="https://control-toolbox.org/CTBase.jl/dev/api/traits#CTBase.Traits.InPlace" target="_blank" rel="noreferrer"><code>InPlace</code></a>) is rejected by <a href="/CTLie.jl/dev/api/api_ctlie_public#CTLie.ad"><code>ad</code></a> and <a href="/CTLie.jl/dev/api/api_ctlie_public#CTLie.∂ₜ"><code>∂ₜ</code></a> with a <a href="https://control-toolbox.org/CTBase.jl/dev/api/exceptions#CTBase.Exceptions.NotImplemented" target="_blank" rel="noreferrer"><code>CTBase.Exceptions.NotImplemented</code></a> error. Reconstruct the field out-of-place before taking brackets or time derivatives:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Xip </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> VectorField</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [x[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">x[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]; is_inplace</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ad</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(Xip, Xip)        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ❌ NotImplemented — ad is not defined for in-place fields</span></span></code></pre></div><h3 id="No-Lie-operations-on-a-Hamiltonian-vector-field" tabindex="-1">No Lie operations on a Hamiltonian vector field <a class="header-anchor" href="#No-Lie-operations-on-a-Hamiltonian-vector-field" aria-label="Permalink to &quot;No Lie operations on a Hamiltonian vector field {#No-Lie-operations-on-a-Hamiltonian-vector-field}&quot;">​</a></h3><p>A <a href="https://control-toolbox.org/CTBase.jl/dev/api/data#CTBase.Data.HamiltonianVectorField" target="_blank" rel="noreferrer"><code>HamiltonianVectorField</code></a> lives on phase space with signature <code>(x, p)</code>, not <code>(x)</code>, so it is <strong>not</strong> a valid operand for the Lie bracket / Lie derivative, nor for the <a href="/CTLie.jl/dev/api/api_ctlie_public#CTLie.Lift"><code>Lift</code></a>. Both raise <a href="https://control-toolbox.org/CTBase.jl/dev/api/exceptions#CTBase.Exceptions.NotImplemented" target="_blank" rel="noreferrer"><code>CTBase.Exceptions.NotImplemented</code></a>:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Z </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> HamiltonianVectorField</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">((x, p) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [x[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]; is_autonomous</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ad</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(Z, Z)            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ❌ NotImplemented — signature is (x, p), not (x)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Lift</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(Z)             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ❌ NotImplemented — Z already lives on phase space</span></span></code></pre></div><p>Use the underlying plain <a href="https://control-toolbox.org/CTBase.jl/dev/api/data#CTBase.Data.VectorField" target="_blank" rel="noreferrer"><code>VectorField</code></a> instead.</p><h3 id="Operands-must-share-traits" tabindex="-1">Operands must share traits <a class="header-anchor" href="#Operands-must-share-traits" aria-label="Permalink to &quot;Operands must share traits {#Operands-must-share-traits}&quot;">​</a></h3><p><a href="/CTLie.jl/dev/api/api_ctlie_public#CTLie.ad"><code>ad</code></a> (on two vector fields) and <a href="/CTLie.jl/dev/api/api_ctlie_public#CTLie.Poisson"><code>Poisson</code></a> (on two Hamiltonians) require their operands to have the <strong>same</strong> time- and variable-dependence. A mismatch raises <a href="https://control-toolbox.org/CTBase.jl/dev/api/exceptions#CTBase.Exceptions.IncorrectArgument" target="_blank" rel="noreferrer"><code>CTBase.Exceptions.IncorrectArgument</code></a>:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Xa </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> VectorField</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [x[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">x[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]];      is_autonomous</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Xt </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> VectorField</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">((t, x) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [x[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">x[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]; is_autonomous</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ad</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(Xa, Xt)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ❌ IncorrectArgument — TD/VD mismatch between X and Y</span></span></code></pre></div><p>The same rule is enforced by <a href="/CTLie.jl/dev/api/api_ctlie_public#CTLie.@Lie"><code>@Lie</code></a>; see <a href="/CTLie.jl/dev/lie_macro#Error-cases">The <code>@Lie</code> macro</a>.</p><h3 id="Plain-functions-default-to-autonomous-and-fixed" tabindex="-1">Plain functions default to autonomous &amp; fixed <a class="header-anchor" href="#Plain-functions-default-to-autonomous-and-fixed" aria-label="Permalink to &quot;Plain functions default to autonomous &amp; fixed {#Plain-functions-default-to-autonomous-and-fixed}&quot;">​</a></h3><p>A bare Julia <code>Function</code> carries no traits, so the operators assume it is autonomous and fixed unless told otherwise via <code>is_autonomous</code> / <code>is_variable</code> (for <code>ad</code>, <code>Poisson</code>, <code>Lift</code>) or the matching keywords of <code>@Lie</code>. When in doubt, wrap the function in a typed <a href="https://control-toolbox.org/CTBase.jl/dev/api/data#CTBase.Data.VectorField" target="_blank" rel="noreferrer"><code>VectorField</code></a> / <a href="https://control-toolbox.org/CTBase.jl/dev/api/data#CTBase.Data.Hamiltonian" target="_blank" rel="noreferrer"><code>Hamiltonian</code></a> so the traits are explicit and checked.</p><h2 id="Configuration" tabindex="-1">Configuration <a class="header-anchor" href="#Configuration" aria-label="Permalink to &quot;Configuration {#Configuration}&quot;">​</a></h2><h3 id="AD-backend" tabindex="-1">AD backend <a class="header-anchor" href="#AD-backend" aria-label="Permalink to &quot;AD backend {#AD-backend}&quot;">​</a></h3><p><code>ad</code>, <code>Poisson</code> and <code>∂ₜ</code> differentiate through a pluggable backend. The default is built on <code>DifferentiationInterface.jl</code> (with <code>ForwardDiff</code> under the hood) and <strong>must be loaded</strong> for gradients/derivatives to be available:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> DifferentiationInterface   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># activates the CTBaseDifferentiationInterface extension</span></span></code></pre></div><p><code>ad_backend</code> takes a <a href="./limitations"><code>Differentiation.AbstractADBackend</code></a> — never a raw <code>ADTypes.AbstractADType</code> — so that the choice of execution device (CPU or GPU) and the choice of underlying AD implementation are both explicit and swappable without touching CTLie itself:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CTBase</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Differentiation</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cpu_backend </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Differentiation</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">DifferentiationInterface</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()                       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># CPU, AutoForwardDiff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gpu_backend </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Differentiation</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">DifferentiationInterface{CTBase.Strategies.GPU}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># GPU, AutoMooncake</span></span></code></pre></div><p>The global default backend is read and set with <a href="/CTLie.jl/dev/api/api_ctlie_public#CTLie.dg_ad_backend"><code>dg_ad_backend</code></a> / <a href="/CTLie.jl/dev/api/api_ctlie_public#CTLie.dg_ad_backend!"><code>dg_ad_backend!</code></a>:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">dg_ad_backend!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(cpu_backend)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># set global default</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">dg_ad_backend</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()               </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># query it</span></span></code></pre></div><p>Every operator also accepts a per-call <code>ad_backend</code> keyword that overrides the global default for that call only — including <a href="/CTLie.jl/dev/api/api_ctlie_public#CTLie.@Lie"><code>@Lie</code></a> via <code>ad_backend=…</code>:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ad</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(X, Y; ad_backend</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cpu_backend)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@Lie</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [X, Y] ad_backend</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cpu_backend</span></span></code></pre></div><h3 id="Code-generation-by-@Lie" tabindex="-1">Code generation by <code>@Lie</code> <a class="header-anchor" href="#Code-generation-by-@Lie" aria-label="Permalink to &quot;Code generation by \`@Lie\` {#Code-generation-by-@Lie}&quot;">​</a></h3><p>The <a href="/CTLie.jl/dev/api/api_ctlie_public#CTLie.@Lie"><code>@Lie</code></a> macro expands to <strong>fully qualified</strong> calls (<code>CTLie._lie_mac</code> / <code>CTLie._poisson_mac</code>, with the trait types <code>CTBase.Traits.*</code>) so that the generated code resolves at the call site regardless of the caller&#39;s module. As a consequence, the macro must be used from a module where both <code>CTLie</code> and <code>CTBase</code> are resolvable — <code>using CTLie</code> plus <code>CTBase</code> importable is enough.</p><h2 id="See-also" tabindex="-1">See also <a class="header-anchor" href="#See-also" aria-label="Permalink to &quot;See also {#See-also}&quot;">​</a></h2><ul><li><p><a href="./">Differential geometry overview</a></p></li><li><p><a href="/CTLie.jl/dev/api/api_ctlie_public#CTLie.ad"><code>ad</code></a>, <a href="/CTLie.jl/dev/api/api_ctlie_public#CTLie.Poisson"><code>Poisson</code></a>, <a href="/CTLie.jl/dev/api/api_ctlie_public#CTLie.Lift"><code>Lift</code></a>, <a href="/CTLie.jl/dev/api/api_ctlie_public#CTLie.∂ₜ"><code>∂ₜ</code></a>, <a href="/CTLie.jl/dev/api/api_ctlie_public#CTLie.@Lie"><code>@Lie</code></a></p></li></ul>`,30)])])}const g=a(n,[["render",l]]);export{c as __pageData,g as default};
